import "core-js/modules/es.array.push.js";
import "core-js/modules/esnext.iterator.constructor.js";
import "core-js/modules/esnext.iterator.filter.js";
import "core-js/modules/esnext.iterator.for-each.js";
import "core-js/modules/esnext.iterator.map.js";
import excel from '../utils/excel.js';
import Request from '../utils/request.js';
import { getIconList, getIconByKey } from '../utils/iconMapping.js';
import CountTo from 'vue-count-to';
export default {
  name: 'MenuManager',
  components: {
    CountTo
  },
  data() {
    return {
      // 数据列表加载动画
      listLoading: true,
      formLabelWidth: '80px',
      iconDict: [],
      checkList: [],
      // 新增/编辑提交表单对象
      dialogForm: {
        name: undefined,
        description: undefined
      },
      // 数据总条数
      total: 0,
      // 表格数据数组
      tableData: [],
      // 新增/编辑 弹出框显示/隐藏
      formVisible: false,
      // 当前对话框模式
      dialogMode: 'add',
      // 'add' or 'edit'
      // 导出数据 弹出框显示/隐藏
      exportVisible: false,
      // 导出进度
      exportProgress: 0,
      // 是否正在导出
      isExporting: false,
      // 导出进度文本
      exportProgressText: '',
      // 防止多次连续提交表单
      isSubmit: false,
      // 菜单统计数据
      menuStats: {
        totalMenus: 0,
        firstLevelMenus: 0,
        secondLevelMenus: 0
      },
      // 表单校验 trigger: ['blur', 'change'] 为多个事件触发
      formRules: {
        // 验证规则
        name: [{
          required: true,
          message: '请填写菜单名称',
          trigger: 'blur'
        }],
        sortNum: [{
          required: true,
          message: '排序不能为空',
          trigger: 'blur'
        }],
        icon: [{
          required: true,
          message: '请选择菜单图标',
          trigger: 'change'
        }]
      }
    };
  },
  created() {
    this.fetchData();
    this.loadIconList();
  },
  methods: {
    // 根据图标key获取对应的图标类
    getIconClass(iconKey) {
      if (!iconKey) return 'el-icon-menu';
      return getIconByKey(iconKey);
    },
    handleDelete(index, row) {
      // console.log(index, row)
      this.$confirm('此操作将删除选中数据, 是否继续?', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        Request.delete("/menu/deleteById/" + row.id).then(response => {
          if (response.code == 0) {
            this.$message({
              type: 'success',
              message: '删除成功!'
            });
            this.fetchData();
          } else {
            this.$message({
              type: 'error',
              errpr: '删除失败!'
            });
          }
        });
      }).catch(() => {
        this.$message({
          type: 'info',
          message: '已取消删除'
        });
      });
    },
    addChildMenu(pid) {
      this.dialogMode = 'add';
      this.formVisible = true;
      this.dialogForm = {
        pid: pid,
        name: '',
        path: '',
        icon: '',
        pagePath: '',
        description: '',
        sortNum: 0
      };
      this.checkList = [];
      this.loadIconList();
    },
    loadIconList() {
      try {
        // 使用 iconMapping.js 中的 getIconList 函数获取图标列表
        this.iconDict = getIconList();
      } catch (error) {
        // 静默处理加载图标列表失败
        this.$message({
          type: 'error',
          message: '加载图标列表失败!'
        });
        this.iconDict = [];
      }
    },
    // 获取数据列表
    async fetchData() {
      this.listLoading = true;
      try {
        const res = await Request.get("/menu/findAll");
        if (res.code === '0') {
          this.tableData = res.data || [];
          this.total = this.tableData.length;
          this.calculateMenuStats();
        } else {}
      } catch (error) {} finally {
        this.listLoading = false;
      }
    },
    openDialog(mode, row = {}) {
      this.dialogMode = mode;
      this.formVisible = true;
      this.loadIconList();
      if (mode === 'edit') {
        this.dialogForm = JSON.parse(JSON.stringify(row));
        this.checkList = this.formatRolesToChinese(row.role);
      } else {
        this.dialogForm = {};
        this.checkList = [];
      }
    },
    // 保存新增/编辑数据
    handleSave(formName) {
      this.dialogForm.role = this.formatRolesToEnglish(this.checkList);
      this.$refs[formName].validate(valid => {
        if (valid) {
          const saveData = {
            ...this.dialogForm,
            pid: this.dialogForm.pid || null
          };
          const request = this.dialogMode === 'add' ? Request.post("/menu/save", saveData) : Request.put("/menu/" + this.dialogForm.id, saveData);
          request.then(response => {
            if (response.code === '0') {
              this.$message({
                showClose: true,
                message: this.dialogMode === 'add' ? '添加成功' : '更新成功',
                type: 'success'
              });
              this.$emit('update:user', this.userInfo);
              this.formVisible = false;
              this.fetchData();
            } else {
              this.$message({
                showClose: true,
                message: response.msg || (this.dialogMode === 'add' ? '添加失败' : '更新失败'),
                type: 'error'
              });
            }
          }).catch(error => {
            // 静默处理保存失败
            this.$message.error('操作失败，请重试');
          }).finally(() => {
            this.isSubmit = false;
          });
        } else {
          this.isSubmit = false;
        }
      });
    },
    // 导出数据--excle格式
    async exportTable(type) {
      if (this.tableData.length) {
        try {
          // 初始化导出状态
          this.isExporting = true;
          this.exportProgress = 0;
          this.exportProgressText = '准备导出...';

          // 进度更新回调函数
          const updateProgress = (progress, text) => {
            this.exportProgress = progress;
            this.exportProgressText = text;
          };

          // 格式化数据（占0-70%）
          updateProgress(10, '正在格式化数据...');
          const exportData = [];

          // 扁平化菜单树数据
          const flattenMenus = menus => {
            let result = [];
            const traverse = items => {
              items.forEach(item => {
                result.push(item);
                if (item.children && item.children.length > 0) {
                  traverse(item.children);
                }
              });
            };
            traverse(menus);
            return result;
          };
          const flatData = flattenMenus(this.tableData);
          for (let i = 0; i < flatData.length; i++) {
            const menu = flatData[i];
            exportData.push({
              id: menu.id || '',
              name: menu.name || '',
              path: menu.path || '',
              icon: menu.icon || '',
              description: menu.description || '',
              pid: menu.pid || '',
              pagePath: menu.pagePath || '',
              sortNum: menu.sortNum || 0,
              role: menu.role || ''
            });

            // 每处理10条更新一次进度
            if ((i + 1) % 10 === 0 || i === flatData.length - 1) {
              const progress = 10 + Math.round((i + 1) / flatData.length * 60);
              updateProgress(progress, `正在格式化数据: ${i + 1}/${flatData.length}`);
              // 使用 setTimeout 让 UI 有机会更新
              await new Promise(resolve => setTimeout(resolve, 0));
            }
          }

          // 导出文件（占70%-100%）
          updateProgress(75, '正在生成文件...');
          const params = {
            header: ['菜单ID', '菜单名', '菜单路径', '菜单图标', '描述', '父级菜单ID', '页面路径', '排序', '菜单所属角色'],
            key: ['id', 'name', 'path', 'icon', 'description', 'pid', 'pagePath', 'sortNum', 'role'],
            data: exportData,
            autoWidth: true,
            fileName: '菜单数据表',
            bookType: type
          };

          // 使用 setTimeout 确保进度条更新
          await new Promise(resolve => setTimeout(resolve, 100));
          updateProgress(90, '正在保存文件...');
          excel.exportDataToExcel(params);

          // 完成
          updateProgress(100, '导出完成！');
          await new Promise(resolve => setTimeout(resolve, 500));
          this.isExporting = false;
          this.exportProgress = 0;
          this.exportProgressText = '';
          this.exportVisible = false;
          this.$message.success('导出成功');
        } catch (error) {
          console.error('导出失败:', error);
          this.isExporting = false;
          this.exportProgress = 0;
          this.exportProgressText = '';
          this.$message.error('导出失败，请稍后重试');
        }
      } else {
        this.$message.warning('暂无数据可导出');
      }
    },
    getMenuRole(role) {
      const roleMap = {
        USER: '普通用户',
        ADMIN: '管理员'
      };

      // 如果role为空，则返回空字符串
      if (!role) {
        return '';
      }

      // 将角色字符串按照逗号分割成数组
      const roles = role.split(',');

      // 使用 map 方法将数组中的每个英文角色转换为中文角色
      const chineseRoles = roles.map(singleRole => roleMap[singleRole]);

      // 使用 join 方法将转换后的中文角色数组连接成一个逗号分隔的字符串
      return chineseRoles.join(',');
    },
    formatRolesToChinese(role) {
      const roleMap = {
        USER: '普通用户',
        ADMIN: '管理员'
      };

      // 如果role为空，则返回空数组
      if (!role) {
        return [];
      }

      // 将角色字符串按照逗号分割成数组，并去除单引号
      const roles = role.split(',').map(singleRole => singleRole.trim().replace(/'/g, ''));

      // 使用 map 方法将数组中的每个英文角色转换为中文角色
      const chineseRoles = roles.map(singleRole => roleMap[singleRole]);

      // 过滤掉未找到映射的项（如果英文角色不在roleMap中）
      const validChineseRoles = chineseRoles.filter(role => role !== undefined);

      // 返回中文角色数组
      return validChineseRoles;
    },
    formatRolesToEnglish(chineseRoles) {
      const roleMap = {
        普通用户: 'USER',
        管理员: 'ADMIN'
      };

      // 如果输入数组为空，则返回空字符串
      if (!chineseRoles || chineseRoles.length === 0) {
        return '';
      }

      // 使用 map 方法将数组中的每个中文角色转换为英文角色
      const englishRoles = chineseRoles.map(singleRole => roleMap[singleRole.trim()]);

      // 使用 join 方法将转换后的英文角色数组连接成一个逗号分隔的字符串
      return englishRoles.join(',');
    },
    // 计算菜单统计数据
    calculateMenuStats() {
      // 统计各级菜单数量
      let firstLevelCount = 0;
      let secondLevelCount = 0;
      let totalCount = 0;

      // 递归遍历菜单树
      const traverseMenus = (menus, level = 1) => {
        menus.forEach(menu => {
          totalCount++;
          if (level === 1) {
            firstLevelCount++;
          } else if (level === 2) {
            secondLevelCount++;
          }

          // 递归遍历子菜单
          if (menu.children && menu.children.length > 0) {
            traverseMenus(menu.children, level + 1);
          }
        });
      };

      // 开始遍历
      traverseMenus(this.tableData);
      this.menuStats = {
        totalMenus: totalCount,
        firstLevelMenus: firstLevelCount,
        secondLevelMenus: secondLevelCount
      };
    }
  }
};
